  return (
    <DialogShapeContext.Provider value={shape}>
      <ButtonShapeProvider shape={shape}>
        <DialogPrimitive.Root
          disablePointerDismissal={disablePointerDismissal ?? !dismissible}
          onOpenChange={handleOpenChange}
